def require_mfa_or_login():
    if is_logged_in():
        return None
    if is_mfa_pending():
        return redirect(url_for("mfa"))
    return redirect(url_for("login", next=request.path))


def verify_totp(user, otp):
    if not pyotp:
        return False
    secret = user.get("totp_secret")
    if not secret:
        return False
    try:
        totp = pyotp.TOTP(secret)
        return totp.verify(str(otp).strip(), valid_window=1)
    except Exception:
        return False


