@app.route("/login", methods=["GET", "POST"])
def login():
    next_url = request.values.get("next") or url_for("home")
    if request.method == "GET":
        if is_logged_in():
            return redirect(next_url)
        if is_mfa_pending():
            return redirect(url_for("mfa", next=next_url))
        return render_template_string(LOGIN_TEMPLATE, error=None, next_url=next_url)

    username = (request.form.get("username") or "").strip()
    password = request.form.get("password") or ""
    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return render_template_string(LOGIN_TEMPLATE, error="Invalid credentials", next_url=next_url), 401

    session.clear()
