def require_api_token():
    authz = request.headers.get("Authorization", "")
    if authz.lower().startswith("bearer "):
        token = authz.split(None, 1)[1].strip()
    else:
        token = request.args.get("access_token") or ""

    if not token or token not in TOKENS:
        abort(401)

    rec = TOKENS.get(token)
    if not rec or token_expired(rec["expires_at"]):
        TOKENS.pop(token, None)
        abort(401)

    username = rec["username"]
    if username not in USERS:
        abort(401)
    return username, rec


@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    api_key = data.get("api_key") or request.headers.get("X-API-Key") or ""

    if not api_key:
        return jsonify({"error": "missing_api_key"}), 401

    client_ok = False
    for client_id, client in API_CLIENTS.items():
        if secrets.compare_digest(client.get("api_key", ""), api_key):
            if username and username in client.get("allowed_users", []):
                client_ok = True
            break

    if not client_ok:
        return jsonify({"error": "invalid_api_key_or_user_not_allowed"}), 403

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "invalid_credentials"}), 401

    token = create_token(username, via="direct-login")
    return jsonify(
        {
            "access_token": token,
            "token_type": "bearer",
            "expires_in": TOKEN_TTL_SECONDS,
            "username": username,
            "mfa_skipped": True,
        }
    )


